import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.http.HttpEntity;
import org.springframework.http.HttpHeaders;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;
import org.springframework.web.client.RestTemplate;
import org.springframework.beans.factory.annotation.Value;

@SpringBootApplication
public class OAuth2Client {
    public static void main(String[] args) {
        SpringApplication.run(OAuth2Client.class, args);
    }
}

@RestController
class AuthorizationController {
    
    private final RestTemplate restTemplate;

    @Value("${oauth2.authorizeUrl}")  // replace with your authorization server's URL
    private String authorizeUrl;

    @Value("${client.id}")             // replace with your client id
    private String clientId;
    
    @Value("${redirect_uri}")          // replace with your redirect URI
    private String redirectUri;
  
    @Value("${scope}")                 // replace with the scope you want to request
    private String scope;

    AuthorizationController(RestTemplateBuilder restTemplateBuilder) {
        this.restTemplate = restTemplateBuilder.build();
    }
    
    @RequestMapping("/authorize")
    public HttpEntity<String> authorize() {
        // Build the authorization URL with client_id, redirect_uri, scope, and response_type parameters
        String url = authorizeUrl + "?client_id=" + clientId 
                    + "&redirect_uri=" + redirectUri 
                    + "&scope=" + scope
                    + "&response_type=code";
        
        HttpHeaders headers = new HttpHeaders();
        headers.setLocation(URI.create(url)); // Redirect to the authorization server URL

        return new ResponseEntity<>(headers, HttpStatus.FOUND);  // Use HTTP 302 Found status code for redirection
    }
}